[asy]
pair A,B,C,D,E;
A=(0,10);
B=(5.9,-8.1);
C=(-9.5,3.1);
D=(9.5,3.1);
E=(-5.9,-8.1);
draw(A--B--C--D--E--cycle,linewidth(0.7));
label("$A$",A,N);
label("$B$",B,SE);
label("$C$",C,NW);
label("$D$",D,NE);
label("$E$",E,SW);
[/asy]
